using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// ─── Configuration ──────────────────────────────────────────

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// Build the chat client with automatic function-call handling
IChatClient client = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

// ─── Tools ──────────────────────────────────────────────────

var noteTool = new NoteTool();

List<AITool> tools =
[
    AIFunctionFactory.Create(WebSearchTool.SearchWeb),
    AIFunctionFactory.Create(noteTool.SaveNote),
    AIFunctionFactory.Create(noteTool.GetNotes),
];

// ─── Interactive loop ───────────────────────────────────────

Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        🔬  AI Research Agent  🔬        ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();
Console.WriteLine("Enter a topic to research (or 'quit' to exit).");
Console.WriteLine();

while (true)
{
    Console.Write("Topic ▸ ");
    var topic = Console.ReadLine()?.Trim();

    if (string.IsNullOrEmpty(topic))
        continue;
    if (topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine();
    Console.WriteLine($"Researching: {topic}");
    Console.WriteLine(new string('─', 60));

    List<ChatMessage> messages =
    [
        new(ChatRole.System, """
            You are a research agent. Investigate the given topic by:
            1. Search the web several times covering different angles of the topic.
            2. Save every important finding as a note using SaveNote.
            3. When you have gathered enough information, call GetNotes to review.
            4. Produce a well-structured, comprehensive summary.
            Perform at least 3 searches before summarizing.
            """),
        new(ChatRole.User,
            $"Research this topic and provide a comprehensive summary: {topic}"),
    ];

    try
    {
        var response = await client.GetResponseAsync(messages, new() { Tools = tools });

        Console.WriteLine();
        Console.WriteLine(new string('─', 60));
        Console.WriteLine("📋  RESEARCH SUMMARY");
        Console.WriteLine(new string('─', 60));
        Console.WriteLine(response.Text);
    }
    catch (Exception ex)
    {
        Console.WriteLine($"\n⚠  Error: {ex.Message}");
    }

    // Reset notes for the next topic
    noteTool.Clear();
    Console.WriteLine();
}

// ═════════════════════════════════════════════════════════════
// Tool: Web Search (DuckDuckGo Lite)
// ═════════════════════════════════════════════════════════════

public static partial class WebSearchTool
{
    private static readonly HttpClient s_http = new()
    {
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Searches the web for the given query and returns relevant result snippets with source URLs.")]
    public static async Task<string> SearchWeb(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🔍  Searching: \"{query}\"");

        try
        {
            var url = $"https://lite.duckduckgo.com/lite?q={WebUtility.UrlEncode(query)}";
            var html = await s_http.GetStringAsync(url);
            return ParseResults(html);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static string ParseResults(string html)
    {
        var sb = new StringBuilder();
        int count = 0;

        // Collect snippets
        foreach (Match m in SnippetRegex().Matches(html))
        {
            if (++count > 6) break;
            var text = WebUtility.HtmlDecode(
                StripTagsRegex().Replace(m.Groups[1].Value, "")).Trim();
            if (!string.IsNullOrWhiteSpace(text))
                sb.AppendLine($"- {text}");
        }

        // Collect source links
        int linkCount = 0;
        foreach (Match m in LinkRegex().Matches(html))
        {
            if (++linkCount > 4) break;
            var href = WebUtility.HtmlDecode(m.Groups[1].Value);
            if (Uri.TryCreate(href, UriKind.Absolute, out _))
                sb.AppendLine($"  Source: {href}");
        }

        return count > 0 ? sb.ToString() : "No results found for this query.";
    }

    [GeneratedRegex("""class="result-snippet"[^>]*>(.*?)</td>""", RegexOptions.Singleline)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex("""<a[^>]+class="result-link"[^>]*href="([^"]*)"""")]
    private static partial Regex LinkRegex();

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex StripTagsRegex();
}

// ═════════════════════════════════════════════════════════════
// Tool: Note Taking
// ═════════════════════════════════════════════════════════════

public sealed class NoteTool
{
    private readonly List<string> _notes = [];

    [Description("Saves a research note. Use this to record important facts, statistics, or insights.")]
    public string SaveNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝  Note #{_notes.Count} saved");
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieves all saved research notes for review and summarization.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        Console.WriteLine($"  📖  Retrieving {_notes.Count} note(s)");
        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
            sb.AppendLine($"[Note {i + 1}] {_notes[i]}");
        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

